import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { toast } from 'react-toastify';
import jsPDF from 'jspdf';
import 'jspdf-autotable';

const Reports = () => {
  const [loading, setLoading] = useState(true);
  const [savings, setSavings] = useState(null);
  const [loans, setLoans] = useState([]);
  const [repayments, setRepayments] = useState(null);
  const [selectedSections, setSelectedSections] = useState({
    summary: true,
    loans: true,
    savings: true,
    repayments: true
  });

  useEffect(() => {
    fetchReports();
  }, []);

  const fetchReports = async () => {
    try {
      setLoading(true);
      const [savingsRes, loansRes, repaymentsRes] = await Promise.all([
        api.get('/admin/reports/savings'),
        api.get('/admin/reports/loans'),
        api.get('/admin/reports/repayments')
      ]);

      // Handle wrapped responses - backend uses success(res, data) which wraps in { data: {...} }
      setSavings(savingsRes.data?.data || savingsRes.data || { total: 0, count: 0 });

      // Loans response is an array
      const loansData = loansRes.data?.data || loansRes.data || [];
      setLoans(Array.isArray(loansData) ? loansData : []);

      setRepayments(repaymentsRes.data?.data || repaymentsRes.data || { total: 0, count: 0 });
    } catch (err) {
      console.error(err);
      toast.error('Failed to fetch reports data');
    } finally {
      setLoading(false);
    }
  };

  const downloadPDF = () => {
    const doc = new jsPDF();
    const currentDate = new Date().toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });

    // Add header with background
    doc.setFillColor(99, 102, 241);
    doc.rect(0, 0, 210, 40, 'F');

    doc.setFontSize(24);
    doc.setTextColor(255, 255, 255);
    doc.setFont('helvetica', 'bold');
    doc.text('Harari Saving & Credit System', 14, 25);

    doc.setFontSize(12);
    doc.setFont('helvetica', 'normal');
    doc.text('Official Financial Performance Report', 14, 33);

    doc.setTextColor(100, 100, 100);
    doc.setFontSize(10);
    doc.text(`Generated on: ${currentDate}`, 14, 50);
    doc.text(`Report ID: HS-${Math.random().toString(36).substr(2, 9).toUpperCase()}`, 14, 55);

    let y = 65;

    if (selectedSections.summary) {
      doc.setFontSize(16);
      doc.setTextColor(31, 41, 55);
      doc.setFont('helvetica', 'bold');
      doc.text('1. Financial Summary', 14, y);

      const summaryData = [
        ['Total Savings Volume', `${savings?.total?.toLocaleString() || 0} ETB`, `${savings?.count || 0} Transactions`],
        ['Total Loan Repayments', `${repayments?.total?.toLocaleString() || 0} ETB`, `${repayments?.count || 0} Payments`],
        ['Net Cash Flow', `${((savings?.total || 0) + (repayments?.total || 0)).toLocaleString()} ETB`, 'Combined Inflow']
      ];

      doc.autoTable({
        startY: y + 5,
        head: [['Metric', 'Amount', 'Volume']],
        body: summaryData,
        theme: 'striped',
        headStyles: { fillColor: [99, 102, 241], textColor: 255, fontStyle: 'bold' },
        styles: { fontSize: 10, cellPadding: 5 },
        alternateRowStyles: { fillColor: [249, 250, 251] }
      });
      y = doc.lastAutoTable.finalY + 15;
    }

    if (selectedSections.loans && loans.length > 0) {
      doc.setFontSize(16);
      doc.setTextColor(31, 41, 55);
      doc.setFont('helvetica', 'bold');
      doc.text('2. Loan Portfolio Distribution', 14, y);

      const loanData = loans.map(loan => [
        loan._id?.toUpperCase() || 'UNKNOWN',
        loan.count.toString(),
        `${loan.total?.toLocaleString() || 0} ETB`,
        `${((loan.total / loans.reduce((acc, l) => acc + (l.total || 0), 0)) * 100).toFixed(1)}%`
      ]);

      doc.autoTable({
        startY: y + 5,
        head: [['Status', 'Applications', 'Total Value', 'Share']],
        body: loanData,
        theme: 'grid',
        headStyles: { fillColor: [139, 92, 246], textColor: 255, fontStyle: 'bold' },
        styles: { fontSize: 10, cellPadding: 5 }
      });
      y = doc.lastAutoTable.finalY + 15;
    }

    // Add footer to all pages
    const pageCount = doc.internal.getNumberOfPages();
    for (let i = 1; i <= pageCount; i++) {
      doc.setPage(i);
      doc.setFontSize(9);
      doc.setTextColor(156, 163, 175);
      doc.text(
        `Harari Saving & Credit Management System - Confidential Report`,
        14,
        doc.internal.pageSize.getHeight() - 10
      );
      doc.text(
        `Page ${i} of ${pageCount}`,
        doc.internal.pageSize.getWidth() - 30,
        doc.internal.pageSize.getHeight() - 10
      );
    }

    doc.save(`Harari-Financial-Report-${new Date().toISOString().split('T')[0]}.pdf`);
    toast.success('Professional PDF report generated!');
  };

  const downloadExcel = () => {
    let csvContent = "data:text/csv;charset=utf-8,";

    // Add header
    csvContent += "Harari Saving & Credit System - Financial Reports\n";
    csvContent += `Generated on: ${new Date().toLocaleDateString()}\n\n`;

    // Summary section (if selected)
    if (selectedSections.summary) {
      csvContent += "Summary Statistics\n";
      csvContent += "Category,Amount,Count\n";
      csvContent += `Total Savings,$${savings?.total || 0},${savings?.count || 0} transactions\n`;
      csvContent += `Total Repayments,$${repayments?.total || 0},${repayments?.count || 0} payments\n\n`;
    }

    // Loan distribution (if selected)
    if (selectedSections.loans && loans.length > 0) {
      csvContent += "Loan Distribution by Status\n";
      csvContent += "Status,Count,Total Amount\n";
      loans.forEach(loan => {
        csvContent += `${loan._id || 'Unknown'},${loan.count},$${loan.total || 0}\n`;
      });
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `Harari-Reports-${new Date().toLocaleDateString()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    toast.success('Excel/CSV downloaded successfully!');
  };

  const toggleSection = (key) => {
    setSelectedSections(s => ({ ...s, [key]: !s[key] }));
  };

  return (
    <div className="fade-in" style={{ paddingBottom: '2rem' }}>
      <div className="flex-between mb-8" style={{ alignItems: 'flex-end' }}>
        <div>
          <h2 className="page-title" style={{ marginBottom: '0.5rem', fontSize: '2rem' }}>📑 Reports & Analytics</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '1rem', margin: 0 }}>
            Comprehensive financial insights and system performance metrics.
          </p>
        </div>
        <div style={{ display: 'flex', gap: '1rem' }}>
          <button
            onClick={fetchReports}
            className="btn btn-secondary"
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '0.5rem',
              padding: '0.75rem 1.25rem',
              borderRadius: '12px',
              background: 'rgba(255,255,255,0.05)'
            }}
            disabled={loading}
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className={loading ? 'rotate-icon' : ''}>
              <path d="M21.5 2v6h-6M2.5 22v-6h6M2 11.5a10 10 0 0 1 18.8-4.3M22 12.5a10 10 0 0 1-18.8 4.2" />
            </svg>
            Refresh
          </button>
          <div className="glass-card" style={{ display: 'flex', gap: '0.75rem', padding: '0.5rem 1rem', borderRadius: '12px', border: '1px solid var(--border)' }}>
            <button
              onClick={downloadPDF}
              className="btn btn-primary hover-glow"
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                padding: '0.5rem 1.25rem',
                borderRadius: '8px',
                fontSize: '0.875rem',
                fontWeight: '700'
              }}
              disabled={loading}
            >
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
                <polyline points="7 10 12 15 17 10" />
                <line x1="12" y1="15" x2="12" y2="3" />
              </svg>
              PDF
            </button>
            <button
              onClick={downloadExcel}
              className="btn btn-primary hover-glow"
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                background: 'var(--success)',
                padding: '0.5rem 1.25rem',
                borderRadius: '8px',
                fontSize: '0.875rem',
                fontWeight: '700'
              }}
              disabled={loading}
            >
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
                <polyline points="7 10 12 15 17 10" />
                <line x1="12" y1="15" x2="12" y2="3" />
              </svg>
              CSV
            </button>
          </div>
        </div>
      </div>

      <div className="glass-card mb-8" style={{ padding: '1.5rem' }}>
        <div style={{ display: 'flex', gap: '2rem', alignItems: 'center' }}>
          <span style={{ fontSize: '0.875rem', color: 'var(--text-muted)', fontWeight: '700', textTransform: 'uppercase' }}>Include in Report:</span>
          <div style={{ display: 'flex', gap: '1.5rem' }}>
            {Object.keys(selectedSections).map(key => (
              <label key={key} style={{
                display: 'flex',
                gap: '0.75rem',
                alignItems: 'center',
                fontSize: '0.9375rem',
                color: 'var(--text-secondary)',
                cursor: 'pointer',
                userSelect: 'none'
              }}>
                <input
                  type="checkbox"
                  checked={selectedSections[key]}
                  onChange={() => toggleSection(key)}
                  style={{
                    width: '18px',
                    height: '18px',
                    accentColor: 'var(--primary)',
                    cursor: 'pointer'
                  }}
                />
                {key.charAt(0).toUpperCase() + key.slice(1)}
              </label>
            ))}
          </div>
        </div>
      </div>

      {loading ? (
        <div className="loading-container" style={{ padding: '4rem' }}>
          <div className="loading-spinner"></div>
          <div style={{ color: 'var(--text-secondary)', marginTop: '1rem' }}>Generating analytics...</div>
        </div>
      ) : (
        <>
