                  <div
                    key={idx}
                    className="hover-lift"
                    style={{
                      padding: '1.5rem',
                      background: 'rgba(255,255,255,0.02)',
                      borderRadius: '16px',
                      border: '1px solid var(--border)',
                      animation: `slideInRight 0.4s ease forwards ${idx * 0.1}s`,
                      opacity: 0
                    }}
                  >
                    <div style={{
                      fontSize: '0.75rem',
                      color: 'var(--text-muted)',
                      marginBottom: '1rem',
                      textTransform: 'uppercase',
                      letterSpacing: '0.1em',
                      fontWeight: 800
                    }}>
                      {loan._id || 'Unknown'}
                    </div>
                    <div style={{ display: 'flex', alignItems: 'baseline', gap: '0.5rem', marginBottom: '0.5rem' }}>
                      <div style={{ fontSize: '2rem', fontWeight: 800, color: 'var(--text-primary)' }}>{loan.count}</div>
                      <div style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>Applications</div>
                    </div>
                    <div style={{
                      fontSize: '1rem',
                      fontWeight: 700,
                      color: loan._id === 'approved' ? 'var(--success)' : loan._id === 'pending' ? 'var(--warning)' : 'var(--danger)'
                    }}>
                      {loan.total?.toLocaleString() || 0} <span style={{ fontSize: '0.75rem', fontWeight: 400 }}>ETB</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="glass-card" style={{ padding: '2rem', background: 'linear-gradient(135deg, rgba(99, 102, 241, 0.05), rgba(168, 85, 247, 0.05))' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1.5rem' }}>
              <div style={{ fontSize: '1.5rem' }}>ℹ️</div>
              <h4 style={{ margin: 0, color: 'var(--text-primary)', fontSize: '1.125rem', fontWeight: 700 }}>
                Report Information & Guidelines
              </h4>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1.5rem' }}>
              <div style={{ color: 'var(--text-secondary)', fontSize: '0.9375rem', lineHeight: '1.6' }}>
                <p style={{ margin: '0 0 0.5rem 0', display: 'flex', gap: '0.75rem' }}>
                  <span style={{ color: 'var(--primary)' }}>•</span>
                  Reports are generated in real-time from the live database.
                </p>
                <p style={{ margin: 0, display: 'flex', gap: '0.75rem' }}>
                  <span style={{ color: 'var(--primary)' }}>•</span>
                  All monetary values are displayed in Ethiopian Birr (ETB).
                </p>
              </div>
              <div style={{ color: 'var(--text-secondary)', fontSize: '0.9375rem', lineHeight: '1.6' }}>
                <p style={{ margin: '0 0 0.5rem 0', display: 'flex', gap: '0.75rem' }}>
                  <span style={{ color: 'var(--primary)' }}>•</span>
                  Export functionality supports both PDF and CSV formats.
                </p>
                <p style={{ margin: 0, display: 'flex', gap: '0.75rem' }}>
                  <span style={{ color: 'var(--primary)' }}>•</span>
                  Use the refresh button to synchronize with the latest data.
                </p>
              </div>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default Reports;
